import os
import joblib
from google.cloud import storage

def download_model_from_gcs(bucket_name, source_blob_name, destination_file_name):
    """Downloads a blob from the bucket."""
    # Initialize a storage client
    storage_client = storage.Client()
    
    # Get the bucket
    bucket = storage_client.bucket(bucket_name)
    
    # Get the blob
    blob = bucket.blob(source_blob_name)
    
    # Download the blob to a local file
    blob.download_to_filename(destination_file_name)

def load_latest_model(model_directory):
    """Loads the latest model from the given directory."""
    # List all files in the directory
    files = os.listdir(model_directory)
    
    # Filter only model files (assuming they have .joblib extension)
    model_files = [f for f in files if f.endswith('.joblib')]
    
    # Sort by modification time, latest first
    model_files.sort(key=lambda x: os.path.getmtime(os.path.join(model_directory, x)), reverse=True)
    
    # Load the latest model
    latest_model_path = os.path.join(model_directory, model_files[0])
    model = joblib.load(latest_model_path)
    
    return model

def main():
    # Get the model path from environment variable
    model_directory = os.getenv('MODEL_PATH')
    
    if not model_directory:
        raise ValueError("MODEL_PATH environment variable is not set.")
    
    # Ensure the directory exists locally
    if not os.path.exists(model_directory):
        os.makedirs(model_directory)
    
    # Download the latest model from GCS (assuming bucket name and blob name are known)
    bucket_name = 'your-bucket-name'
    source_blob_name = 'path/to/latest/model.joblib'  # Replace with actual path
    destination_file_name = os.path.join(model_directory, 'latest_model.joblib')
    
    download_model_from_gcs(bucket_name, source_blob_name, destination_file_name)
    
    # Load the latest model
    model = load_latest_model(model_directory)
    
    print("Model loaded successfully:", model)

if __name__ == "__main__":
    main()